    const idx = (r.chunk_index !== undefined && r.chunk_index !== null) ? ` chunk=${r.chunk_index}` : "";
    const body = (r.content || "").trim();
    return `FILE: ${file}${idx}${d}\n${body}`.trim();
  })
  .filter(Boolean)
  .join("\n\n---\n\n");

