    const pred = r.predicate || r.pred_iri || r.pred || "";
    const obj  = r.object || r.obj_iri || r.obj_literal || r.obj || "";
    const conf = (r.confidence !== undefined && r.confidence !== null) ? ` conf=${Number(r.confidence).toFixed(2)}` : "";
    const ev = (r.evidence_text || r.evidence || "").trim();

    const tripleLine = `${subj} | ${pred} | ${obj}`.trim();
    if (!tripleLine.replace(/\|/g, "").trim()) return null;

    return `FILE: ${file}${conf}\n${tripleLine}${ev ? `\nEVIDENCE: "${ev}"` : ""}`.trim();
  })
  .filter(Boolean)
  .join("\n");

