  json: {
    embedding_context,
    kg_context,
    kg_context_with_files,
  }
}];

function parseMessage(m) {
  if (m == null) return { isAssistant: false, text: "" };

  // message might already be object, or a JSON string, or plain text
  let obj = null;
  if (typeof m === "object") obj = m;
  else {
    const s = String(m);
    try { obj = JSON.parse(s); }
    catch { return { isAssistant: false, text: s }; }
  }

  // Detect assistant rows robustly
