function pickText(resp) {
  const r = resp?.body ?? resp ?? {};
  return (
    r.output_text ??
    r?.output?.[0]?.content?.[0]?.text ??
    (Array.isArray(r?.output?.[0]?.content)
      ? r.output[0].content.map(c => c?.text).filter(Boolean).join("")
      : null) ??
    r.response_text ??
    null
  );
}

