  // HTTP response from OpenAI
  const resp = item.json?.body ?? item.json ?? {};
  const txt = pickText(resp);
  if (!txt) throw new Error("No model output text found in HTTP response.");

  let out;
  try { out = JSON.parse(txt); }
  catch (e) {
    throw new Error("Model output is not valid JSON. First 300 chars: " + String(txt).slice(0, 300));
  }

  // Pull ids from the paired Loop Chunks item
  const chunkRow = $item(i).$node["Loop Chunks"].json || {};
  const chunk_id = chunkRow.chunk_id;
  const document_id = chunkRow.document_id;

  if (!chunk_id || !document_id) {
    throw new Error("chunk_id/document_id missing from Loop Chunks paired item.");
  }

  // Normalize entities to array-of-objects for jsonb_to_recordset
  const entitiesRaw = Array.isArray(out.entities) ? out.entities : [];
  const entities = entitiesRaw
    .map(e => {
      if (typeof e === "string") return { entity_iri: e, label: null, type_iri: null };
      return {
        entity_iri: e.entity_iri ?? e.iri ?? e.id ?? e.key ?? null,
        label: e.label ?? null,
        type_iri: e.type_iri ?? e.type ?? null
      };
    })
    .filter(e => !!e.entity_iri);

  // Normalize triples to the DB column names used by Insert KG Triples
  const triplesRaw = Array.isArray(out.triples) ? out.triples : [];
  const triples = triplesRaw
    .map(t => ({
      subj_iri: t.subj_iri ?? t.subject ?? t.s ?? null,
      pred_iri: t.pred_iri ?? t.predicate ?? t.p ?? null,
      obj_iri:  t.obj_iri  ?? t.object ?? t.o ?? null,
      obj_literal: t.obj_literal ?? t.literal ?? null,
      obj_datatype_iri: t.obj_datatype_iri ?? t.datatype_iri ?? null,
      obj_lang: t.obj_lang ?? t.lang ?? null,
      is_literal: !!(t.is_literal ?? (t.obj_literal != null)),
      confidence: t.confidence ?? null,
      evidence: t.evidence ?? t.evidence_text ?? null
    }))
    .filter(t => t.subj_iri && t.pred_iri && (t.obj_iri || t.obj_literal));

  return {
    json: {
      chunk_id,
      document_id,
      entities_json: JSON.stringify(entities),
      triples_json: JSON.stringify(triples)
    }
  };
});

