function extractText(j) {
  // Gemini node outputs: content.parts[].text
  const parts = j?.content?.parts;
  if (Array.isArray(parts)) {
    const t = parts.map(p => p?.text).filter(Boolean).join("").trim();
    if (t) return t;
  }

  // Fallbacks
  return String(
    j?.text ??
    j?.outputText ??
    j?.output ??
    j?.ocr_text ??
    ""
  ).trim();
}

function b64(s) {
  return Buffer.from(String(s ?? ""), "utf8").toString("base64");
}

function safeName(s) {
  return String(s ?? "")
    .replace(/[^\w.\-]+/g, "_")
    .replace(/_+/g, "_")
    .replace(/^_+|_+$/g, "")
    .slice(0, 180) || "uploaded_file";
}

return items.map((item) => {
  const j = item.json || {};
  const bin = item.binary?.data || {};

  const ocr_text_raw = extractText(j);
  const ocr_text = ocr_text_raw.length ? ocr_text_raw : "[NO_TEXT]";

  const filename = j.filename || bin.fileName || "uploaded_file";
  const mime_type = j.mime_type || bin.mimeType || "application/pdf";
  const bytes = j.bytes ?? bin.fileSize ?? null;

  // Prefer stable IDs when available, else unique-per-upload to avoid overwrites
  const original_key = j.original_binary_key || "data";
  const nonce = `${Date.now()}_${Math.random().toString(16).slice(2)}`;

  const external_id =
    (j.external_id && String(j.external_id).trim()) ||
    (j.original_doc_id && String(j.original_doc_id).trim()) ||
    (bytes ? `n8n:${safeName(filename)}:${bytes}:${original_key}` : `n8n:${safeName(filename)}:${original_key}:${nonce}`);

  const ocr_engine = j.ocr_engine || "gemini_document_node";
  const ocr_model = j.ocr_model || j.model || j.modelId || "models/gemini-2.5-flash";

  // Minimal raw response (no citations payload)
  const raw_obj = {
    finishReason: j.finishReason || null,
    bytes,
    model: ocr_model,
  };
  const raw_json = JSON.stringify(raw_obj);

  // Base64 params for your OCR SQL (expects 7 params)
  const pg_params = [
    b64(external_id),
    b64(filename),
    b64(mime_type),
    b64(ocr_engine),
    b64(ocr_model),
    b64(ocr_text),
    b64(raw_json),
  ];

  return {
    json: {
      ...j,
      external_id,
      filename,
      mime_type,
      bytes,
      ocr_engine,
      ocr_model,
      ocr_text,
      raw_response: raw_obj,
      pg_params,               // use this in Postgres node Query Parameters: {{ $json.pg_params }}
      pg_params_csv: pg_params.join(","), // optional
    },
    binary: item.binary,
  };
});

const out = [];

for (const item of items) {
  const json = item.json || {};
  const bins = item.binary || {};
  const keys = Object.keys(bins);

  // If it's already normalized, pass through
  if (keys.length === 1 && keys[0] === "data") {
    out.push(item);
    continue;
  }

  for (const key of keys) {
    const bin = bins[key];
    if (!bin?.data) continue;

    out.push({
      json: {
        ...json,
        original_binary_key: key,
        filename: bin.fileName || json.filename || key,
        mime_type: bin.mimeType || json.mime_type || "application/octet-stream",
      },
      binary: {
        data: bin, // rename to "data"
      },
    });
  }
}

return out;

function b64(s) {
