}

const chunks = $('Execute a SQL query10').all().map(i => i.json);

if (chunks.length !== items.length) {
  throw new Error(`Count mismatch: chunks=${chunks.length}, embeddings=${items.length}`);
}

return items.map((resp, i) => {
  const chunk = chunks[i];

  const emb =
    resp.json?.data?.[0]?.embedding ??
    resp.json?.data?.embedding ??
    resp.json?.embedding;

  if (!Array.isArray(emb) || emb.length === 0) {
    throw new Error(`Missing embedding at index ${i}`);
  }

  const embedding_txt = `[${emb.join(',')}]`;

  const pg_params_csv = [
    b64(chunk.chunk_id),      // $1
    b64(embedding_txt),       // $2
  ].join(",");

  return {
    json: {
      chunk_id: chunk.chunk_id,
      document_id: chunk.document_id,
      external_id: chunk.external_id ?? null,
      filename: chunk.filename ?? "unknown_file",
      chunk_index: chunk.chunk_index ?? 0,
      content: chunk.content ?? "",
      embedding: embedding_txt,
      pg_params_csv,
    }
  };
});

const body = $json.body || {};
const email = String(body.email ?? '').trim().toLowerCase();
const password = String(body.password ?? '');
const rememberDevice = !!body.rememberDevice;

const esc = (s) => String(s).replace(/'/g, "''");

return [{
  json: {
    email,
    password,
    email_esc: esc(email),
    password_esc: esc(password),
    rememberDevice
  }
}];

const hits = items.map(i => i.json);

const chunk_ids = [...new Set(hits.map(h => h.chunk_id).filter(Boolean))];
const doc_ids   = [...new Set(hits.map(h => h.document_id).filter(Boolean))];

// Postgres-friendly uuid[] array literals
const chunk_ids_pg = `{${chunk_ids.join(",")}}`; // -> '{}' if empty
const doc_ids_pg   = `{${doc_ids.join(",")}}`;

return [{ json: { chunk_ids, doc_ids, chunk_ids_pg, doc_ids_pg } }];

// Try these node names in order (add/rename if needed)
const VECTOR_NODE_CANDIDATES = [
  "Execute a SQL query16",
  "Execute a SQL query4",
  "Execute a SQL query", // fallback if you renamed
];

const MAX_CHUNKS = 3;
const MAX_CHUNK_CHARS = 1200;
const MAX_TRIPLES = 60;
const MAX_EVIDENCE_CHARS = 240;

function trunc(s, n) {
  const t = String(s || "");
  return t.length > n ? t.slice(0, n) + "…" : t;
}

function getNodeRows(nodeName) {
  try {
    // Recommended in n8n: $(nodeName).all()
    return $(nodeName).all().map(x => x.json);
  } catch (e) {}

  try {
    // Fallback some setups
    return $items(nodeName).map(x => x.json);
  } catch (e) {}

  return [];
}

// 1) Vector search hits (document chunks)
let embedHits = [];
let vectorNodeUsed = null;

for (const n of VECTOR_NODE_CANDIDATES) {
  const rows = getNodeRows(n);

  // Detect "vector hit" rows by presence of chunk content + distance
  const looksLikeVectorHits = rows.some(r =>
    (r.content || r.chunk_id || r.document_id) &&
    (r.dist !== undefined || r.d !== undefined || r.distance !== undefined)
  );

  if (rows.length && looksLikeVectorHits) {
    embedHits = rows;
    vectorNodeUsed = n;
    break;
  }
}

// 2) KG rows arrive as input items to this node (your current wiring)
const kgRows = $input.all().map(i => i.json);

// Build embedding context (top N chunks)
const embedding_context = embedHits
  .slice(0, MAX_CHUNKS)
  .map(r => {
    const file =
      r.filename ||
      r.doc_filename ||
      r.source_filename ||
      "UNKNOWN_FILE";

    const distVal = (r.dist ?? r.d ?? r.distance);
    const dist = (distVal !== undefined && distVal !== null)
      ? ` dist=${Number(distVal).toFixed(3)}`
      : "";

    const idx = (r.chunk_index !== undefined && r.chunk_index !== null)
      ? ` chunk=${r.chunk_index}`
      : "";

    const body = trunc((r.content || "").trim(), MAX_CHUNK_CHARS);
    return `FILE: ${file}${idx}${dist}\n${body}`.trim();
  })
  .filter(Boolean)
  .join("\n\n---\n\n");

// Build KG context with file + triple + evidence
const kg_context_with_files = kgRows
  .slice(0, MAX_TRIPLES)
  .map(r => {
    const file = r.filename || r.document_id || "UNKNOWN_FILE";
    const subj = r.subject || "";
    const pred = r.predicate || "";
    const obj  = r.object || "";

    const conf = (r.confidence !== undefined && r.confidence !== null)
      ? ` conf=${Number(r.confidence).toFixed(2)}`
      : "";

    const ev = trunc((r.evidence_text || "").trim(), MAX_EVIDENCE_CHARS);

    const tripleLine = `${subj} | ${pred} | ${obj}`.trim();
    if (!tripleLine.replace(/\|/g, "").trim()) return null;

    return `FILE: ${file}${conf}\n${tripleLine}${ev ? `\nEVIDENCE: "${ev}"` : ""}`.trim();
  })
  .filter(Boolean)
  .join("\n");

// Plain triple-only KG context
const kg_context = kgRows
  .slice(0, MAX_TRIPLES)
  .map(r => {
    const subj = r.subject || "";
    const pred = r.predicate || "";
    const obj  = r.object || "";
    const tripleLine = `${subj} | ${pred} | ${obj}`.trim();
    return tripleLine.replace(/^\|\s*|\s*\|$/g, "");
  })
  .filter(Boolean)
  .join("\n");

return [{
  json: {
    embedding_context,
    kg_context,
    kg_context_with_files,

    // Minimal debug so you can confirm it’s pulling the right node
    _debug_vector_node: vectorNodeUsed,
    _debug_embed_hits: embedHits.length,
    _debug_kg_rows: kgRows.length,
  }
}];

