WITH params AS (
  SELECT
    NULLIF(
      '{{ (() => {
          const b = $("Webhook2").first().json.body || {};

          const sid =
            b.sessionId || b.sessionid || b.session_id;

          const tenant =
            b.tenantId || b.tenantid || b.tenant_id;

          const user =
            b.userId || b.userid || b.user_id;

          const chat =
            b.chatId || b.chatid || b.chat_id;

          // Prefer explicit sessionId if provided, else build the stored composite key (COLON-separated)
          return (sid && String(sid)) || (tenant && user && chat ? `${tenant}:${user}:${chat}` : (chat || ""));
      })() }}',
      ''
    )::text AS session_id
)
SELECT
  id,
  session_id,
  message
FROM public.router_chat
WHERE session_id = (SELECT session_id FROM params)
ORDER BY id DESC
LIMIT 50;

