function parseMessage(m) {
  if (m == null) return { isAssistant: false, text: "" };

  let obj = null;
  if (typeof m === "object") obj = m;
  else {
    const s = String(m);
    try { obj = JSON.parse(s); }
    catch { return { isAssistant: false, text: s }; }
  }

  const isAssistant =
    obj.assistant === true ||
    obj.role === "assistant" ||
    obj.type === "ai" ||
    obj.type === "assistant" ||
    obj.isAssistant === true;

  const text =
    obj.content ??
    obj.text ??
    obj.message ??
    obj.data?.content ??
    obj.kwargs?.content ??
    "";

  return { isAssistant, text: String(text || "").trim() };
}

const rows = $input.all().map(i => i.json);
rows.reverse();

const userTexts = [];
for (const r of rows) {
  const p = parseMessage(r.message);
  if (!p.isAssistant && p.text) userTexts.push(p.text);
}

const last10Users = userTexts.slice(-10);
const q = String($('Guardrails1').item.json.guardrailsInput || "").trim();

const embedding_input =
  last10Users.length
    ? `${q}\n\nRecent user messages:\n- ${last10Users.join("\n- ")}`
    : q;

// expose tenant_id for downstream nodes if needed
const tenant_id = $('Webhook2').item.json.body.tenantId || $('Webhook2').item.json.body.tenant_id || null;

return [{ json: { embedding_input, last10UsersCount: last10Users.length, tenant_id } }];
